    def slope(i, j):
        return (pts[j] - pts[i]) / (j - i)

    def check_with_slope(s):
        line1 = set()
        for i in range(n):
            if (pts[i] - pts[0]) == s * i:
                line1.add(i)
        if len(line1) == n:
            return False
        line2 = [i for i in range(n) if i not in line1]
        if len(line2) <= 1:
            return True
        s2 = (pts[line2[1]] - pts[line2[0]]) / (line2[1] - line2[0])
        if abs(s2 - s) > 1e-9:
            return False
        for i in line2[2:]:
